            ObjectInput in = new ObjectInputStream(bis);

            Object obj = in.readObject();
            System.out.println(obj);  // This line will execute any code present in the deserialized object

        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
        }
